/// <summary>
/// Determines if concurrent deletes should throw exception.
/// </summary>
/// <returns>true, if exception should be thrown; otherwise, false.</returns>
public boolean shouldThrowExceptionOnZeroDelete()
{
    return true;
}

    [SysClientCacheDataMethodAttribute(true)]
    public display NoYesId noWritesDisplay()
    {
        NoYesId  res;
        DEVLicenseTablesObjectLink		licenseTablesObjectLink;
        DEVLicenseTablesUsers			licenseTablesUsers;
        if (this.CurrentAccessLevel == AccessLevel::Write)
        {
			//do we have any record for this object
            select firstonly RecId from licenseTablesObjectLink
				where licenseTablesObjectLink.EntitlementObject == this.EntitlementObject
            join licenseTablesUsers
                where licenseTablesUsers.TableName == licenseTablesObjectLink.TableName;

			if (licenseTablesObjectLink.RecId)
            {
                licenseTablesObjectLink = null;
                licenseTablesUsers      = null;

                select firstonly RecId from licenseTablesObjectLink
					where licenseTablesObjectLink.EntitlementObject == this.EntitlementObject
				join licenseTablesUsers
					where licenseTablesUsers.TableName == licenseTablesObjectLink.TableName &&
                          licenseTablesUsers.UserId    == this.UserId;
				if (!licenseTablesObjectLink.RecId)
                {
                    res = true;
				}

			}

		}
		return res;
    }
